```class Solution {
    public int maximumLength(String s) {
        int maxLen = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            int count = 1;
            for (int j = i + 1; j < s.length(); j++) {
                if (s.charAt(j) == c) {
                    count++;
                } else {
                    break;
                }
            }
            if (count >= 3) {
                maxLen = Math.max(maxLen, count);
            }
        }
        return maxLen == 1 ? -1 : maxLen;
    }
}```
